const { ethers } = require("ethers");
require('dotenv').config();

// Contract bytecode and ABI (simplified version)
const BATCH_SPINS_BYTECODE = "";

const BATCH_SPINS_ABI = [
  {
    "inputs": [
      {"internalType": "address", "name": "_cUSDToken", "type": "address"},
      {"internalType": "address", "name": "_liquidityPool", "type": "address"}
    ],
    "stateMutability": "nonpayable",
    "type": "constructor"
  },
  {
    "inputs": [
      {"internalType": "uint256", "name": "spinCount", "type": "uint256"},
      {"internalType": "uint256", "name": "spinAmount", "type": "uint256"}
    ],
    "name": "batchSpins",
    "outputs": [
      {"internalType": "bool", "name": "success", "type": "bool"},
      {"internalType": "uint256", "name": "totalGasUsed", "type": "uint256"}
    ],
    "stateMutability": "nonpayable",
    "type": "function"
  },
  {
    "inputs": [],
    "name": "cUSDToken",
    "outputs": [
      {"internalType": "address", "name": "", "type": "address"}
    ],
    "stateMutability": "view",
    "type": "function"
  },
  {
    "inputs": [],
    "name": "liquidityPool",
    "outputs": [
      {"internalType": "address", "name": "", "type": "address"}
    ],
    "stateMutability": "view",
    "type": "function"
  }
];

async function main() {
  console.log("🚀 DEPLOYING AGROSHIELD BATCH SPINS CONTRACT");
  console.log("============================================");
  
  const provider = new ethers.JsonRpcProvider("https://forno.celo.org");
  const wallet = new ethers.Wallet(process.env.PRIVATE_KEY, provider);
  
  console.log("👤 Deployer Address:", wallet.address);
  
  // Check balance
  const balance = await provider.getBalance(wallet.address);
  console.log("💰 CELO Balance:", ethers.formatEther(balance), "CELO");
  
  if (balance < ethers.parseEther("0.1")) {
    console.log("❌ Insufficient CELO for deployment (need ~0.1 CELO)");
    return;
  }
  
  // Contract parameters
  const cUSDToken = "0x765DE816845861e75A25fCA122bb6898B8B1282a";
  const liquidityPool = "0x0e40c31eb5e729af7f417dcbe6f2cecb826c5ba6";
  
  console.log("📋 Contract Parameters:");
  console.log("   💰 cUSD Token:", cUSDToken);
  console.log("   🏊 Liquidity Pool:", liquidityPool);
  
  try {
    // Deploy contract
    console.log("🔨 Deploying contract...");
    const factory = new ethers.ContractFactory(BATCH_SPINS_ABI, BATCH_SPINS_BYTECODE, wallet);
    
    const contract = await factory.deploy(cUSDToken, liquidityPool);
    console.log("📤 Deployment TX:", contract.deploymentTransaction().hash);
    console.log("⏳ Waiting for confirmation...");
    
    await contract.waitForDeployment();
    const contractAddress = await contract.getAddress();
    
    console.log("✅ Contract deployed successfully!");
    console.log("📍 Contract Address:", contractAddress);
    
    // Verify deployment
    console.log("🔍 Verifying deployment...");
    const cUSDTokenAddress = await contract.cUSDToken();
    const liquidityPoolAddress = await contract.liquidityPool();
    
    console.log("✅ Verification:");
    console.log("   💰 cUSD Token:", cUSDTokenAddress);
    console.log("   🏊 Liquidity Pool:", liquidityPoolAddress);
    
    // Update the batch spin script with the new address
    console.log("\n📝 Updating batch spin script...");
    const fs = require('fs');
    const scriptPath = '/Users/h/Documents/CascadeProjects/agroshield/scripts/batch-spin-optimized.cjs';
    
    if (fs.existsSync(scriptPath)) {
      let scriptContent = fs.readFileSync(scriptPath, 'utf8');
      scriptContent = scriptContent.replace(
        'const BATCH_SPINS_ADDRESS = "0xTODO";',
        `const BATCH_SPINS_ADDRESS = "${contractAddress}";`
      );
      fs.writeFileSync(scriptPath, scriptContent);
      console.log("✅ Batch spin script updated with new contract address");
    }
    
    console.log("\n🎊 DEPLOYMENT COMPLETE!");
    console.log("🔗 Explorer: https://celoscan.io/address/" + contractAddress);
    console.log("🚀 Ready to run: node scripts/batch-spin-optimized.cjs");
    
  } catch (error) {
    console.error("❌ Deployment failed:", error.message);
    
    if (error.message.includes("insufficient funds")) {
      console.log("💡 Add more CELO to your wallet");
    } else if (error.message.includes("nonce")) {
      console.log("💡 Wait for pending transactions to complete");
    } else if (error.message.includes("gas")) {
      console.log("💡 Try increasing gas limit");
    }
  }
}

main()
  .then(() => process.exit(0))
  .catch((error) => {
    console.error("Script failed:", error);
    process.exit(1);
  });
